bool containsNearbyAlmostDuplicate(int* nums, int n, int k, int t) {
    if (k < 1 || t < 0) return false;
    for (int i = 0; i < n; i++)
        for (int j = i + 1; j <= i + k && j < n; j++) {
            long long d = (long long)nums[i] - nums[j];
            if (d < 0) d = -d;
            if (d <= t) return true;
        }
    return false;
}
